import{_ as e,c as n,a1 as s,o}from"./chunks/framework.BDxlaA_J.js";const p=JSON.parse('{"title":"MAC Address Spoofing","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/7-sniffing/2-Spoofing-MAC-address.md","filePath":"categories/ethical-hacking-labs/7-sniffing/2-Spoofing-MAC-address.md"}'),i={name:"categories/ethical-hacking-labs/7-sniffing/2-Spoofing-MAC-address.md"};function t(r,a,l,d,c,h){return o(),n("div",null,a[0]||(a[0]=[s('<h1 id="mac-address-spoofing" tabindex="-1">MAC Address Spoofing <a class="header-anchor" href="#mac-address-spoofing" aria-label="Permalink to &quot;MAC Address Spoofing&quot;">​</a></h1><p>MAC spoofing is a technique for changing a factory-assigned Media Access Control (MAC) address of a network interface on a networked device. The MAC address that is hard-coded on a network interface controller (NIC) cannot be changed. However, many drivers allow the MAC address to be changed. Additionally, there are tools which can make an operating system believe that the NIC has the MAC address of a user&#39;s choosing. The process of masking a MAC address is known as MAC spoofing. Essentially, MAC spoofing entails changing a computer&#39;s identity, for any reason, and it is relatively easy.</p><p align="center"><img src="https://d5ngkkf53wl41.cloudfront.net/tutorials/ethical-hacking/mac-address-spoofing.png"></p><h3 id="why-changing-mac-address" tabindex="-1">Why changing MAC address? <a class="header-anchor" href="#why-changing-mac-address" aria-label="Permalink to &quot;Why changing MAC address?&quot;">​</a></h3><ul><li>Increase anonymity.</li><li>Impersonate other devices.</li><li>Bypass filters.</li></ul><p><strong>note</strong>: the lab will show how to change your MAC address only on the memory not physically.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Change MAC address on <strong>Kali Linux</strong>.</li><li>Change MAC address on <strong>Windows</strong>.</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Kali Linux virtual machine.</li><li>Alfa network adapter, or other with similar chipset. <a href="https://kennyvn.com/best-wireless-adapters-kali-linux/" target="_blank" rel="noreferrer">[+]</a></li><li>Windows 7, 8 or 10 virtual machine.</li></ul><h2 id="using-macchanger-kali" tabindex="-1">Using <code>macchanger</code> (Kali) <a class="header-anchor" href="#using-macchanger-kali" aria-label="Permalink to &quot;Using `macchanger` (Kali)&quot;">​</a></h2><p>Macchanger is a tool that is included with any version of Kali Linux rolling edition and can change the MAC address to any desired address until the next reboot. In this lab we will be spoofing the MAC address of our wireless adapter with a random MAC address generated by <strong>Macchanger on Kali Linux.</strong></p><p>Repo: <a href="https://github.com/alobbs/macchanger" target="_blank" rel="noreferrer">https://github.com/alobbs/macchanger</a></p><ol start="0"><li><p>Use <code>ifconfig</code> to see your current MAC address of your Network adapter: <code>ifconfig</code></p></li><li><p>Turn off the Network adapter: <code>ifconfig wlan1 down</code></p></li><li><p>Next, change your MAC address to a new random MAC Address using <code>macchanger</code>: <code>macchanger -r wlan1</code></p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Current MAC:   f2:30:a0:1a:41:b3 (unknown)</span></span>\n<span class="line"><span>Permanent MAC: 00:c1:c8:a1:e7:d1 (ALFA, INC.)</span></span>\n<span class="line"><span>New MAC:       ce:11:9a:98:fe:ad (unknown)</span></span></code></pre></div><h2 id="changing-mac-address-manually-kali" tabindex="-1">Changing MAC address manually (Kali) <a class="header-anchor" href="#changing-mac-address-manually-kali" aria-label="Permalink to &quot;Changing MAC address manually (Kali)&quot;">​</a></h2><ol start="0"><li><p>Turn off the Network adapter: <code>ifconfig wlan0 down</code></p></li><li><p>Change the address using <code>hw ether</code> option from <strong>ifconfig</strong> using any MAC address you want: <code>ifconfig wlan0 hw ether 00:11:22:33:44:55</code></p></li><li><p>Enable the interface: <code>ifconfig wlan0 up</code></p></li><li><p>Check the changes of the network adapter: <code>ifconfig</code></p></li></ol><hr><h2 id="smac-gui-tool-windows" tabindex="-1">SMAC GUI Tool (Windows) <a class="header-anchor" href="#smac-gui-tool-windows" aria-label="Permalink to &quot;SMAC GUI Tool (Windows)&quot;">​</a></h2><p>SMAC is a powerful and easy-to-use tool for MAC address changer (spoofer). The tool can activate a new MAC address right after changing it automatically.</p><p><a href="https://smac.soft32.com/" target="_blank" rel="noreferrer">https://smac.soft32.com/</a></p><p><img src="https://thegeekpage.com/wp-content/uploads/2016/05/mac-address-changer-tool.gif" alt="smac"></p>',22)]))}const f=e(i,[["render",t]]);export{p as __pageData,f as default};
